你好，现在你是一名熟练运用processing的视觉游戏设计师，现在我给你看看我的代码：
Stone stone;
Stone stationaryStone;
boolean isFired = false;
boolean isHit = false;
float targetX, targetY;
float targetSize = 50;
int score = 0;
float maxCharge = 20;
long mousePressedTime = 0;
boolean charging = false;

void setup() {
  size(800, 600);
  resetStone();
  resetTarget();
  stationaryStone = new Stone(20, width / 4, height / 2, 0.3, false);
}

void resetStone() {
  stone = new Stone(20, 100, height / 2, 0.3);
  isFired = false;
}

void resetTarget() {
  targetX = random(width / 2, width - 50);
  targetY = random(50, height - 50);
}

void draw() {
  background(255);
  stationaryStone.draw();

  if (!stationaryStone.isFired) {
    stationaryStone.x = width / 4; // Keep stationary stone at its place
  }

  stone.update();
  stone.draw();

  if (stone.isFired && !stationaryStone.isFired 
      && stone.checkCollision(stationaryStone.x, stationaryStone.y, stationaryStone.size)) {
    handleCollision();
  }

  if (stationaryStone.isFired) {
    stationaryStone.update();
  }

  if (stationaryStone.checkCollision(targetX, targetY, targetSize)) {
    isHit = true;
    score++;
    resetStone();
    resetTarget();
    stationaryStone = new Stone(20, width / 4, height / 2, 0.3, false);
  }

  if (stone.x > width || stone.y < 0 || stone.y > height || stationaryStone.x > width) {
    resetStone();
    stationaryStone = new Stone(20, width / 4, height / 2, 0.3, false);
  }

  if (charging) {
    float chargeRadius = map(millis() - mousePressedTime, 0, 1000, stone.size, stone.size * 3);
    noFill();
    stroke(255, 0, 0);
    ellipse(stone.x, stone.y, chargeRadius * 2, chargeRadius * 2);
  }

  stroke(0);
  if (mousePressed && !isFired) {
    line(stone.x, stone.y, mouseX, mouseY);
  }

  fill(0);
  textAlign(RIGHT, TOP);
  textSize(24);
  text("Score: " + score, width - 20, 20);
}

void mousePressed() {
  if (!isFired) {
    mousePressedTime = millis();
    charging = true;
  }
}

void mouseReleased() {
  if (!isFired) {
    float pressTime = millis() - mousePressedTime;
    pressTime = constrain(pressTime, 0, 1000);
    float power = map(pressTime, 0, 1000, 0, maxCharge);
    float angle = atan2(mouseY - stone.y, mouseX - stone.x);
    stone.fire(power, angle);
    isFired = true;
    charging = false;
  }
}

void handleCollision() {
  float m1 = stone.size;
  float m2 = stationaryStone.size;
  PVector v1Initial = stone.velocity.copy();
  PVector v2Initial = new PVector(0, 0);

  PVector v1Final = new PVector((m1 - m2) / (m1 + m2) * v1Initial.x, v1Initial.y);
  PVector v2Final = new PVector((2 * m1) / (m1 + m2) * v1Initial.x, v1Initial.y);

  stone.isFired = false; 
  stone.velocity.set(v1Final);
  stationaryStone.velocity.set(v2Final);
  stationaryStone.isFired = true;
}


Stone 类：
class Stone {
  float size;
  float x, y;
  PVector velocity;
  PVector acceleration;
  float gravity;
  boolean isFired;
  ArrayList<PVector> trail;

  Stone(float size, float x, float y, float gravity) {
    this.size = size;
    this.x = x;
    this.y = y;
    this.gravity = gravity;
    velocity = new PVector(0, 0);
    acceleration = new PVector(0, 0);
    isFired = false;
    trail = new ArrayList<PVector>();
  }

  Stone(float size, float x, float y, float gravity, boolean isFired) {
    this(size, x, y, gravity);
    this.isFired = isFired;
  }

  void update() {
    if (isFired) {
      acceleration.add(new PVector(0, gravity));
      velocity.add(acceleration);
      x += velocity.x;
      y += velocity.y;
      acceleration.mult(0);
      trail.add(new PVector(x, y));
      if (trail.size() > 10) trail.remove(0);
    }
  }

  void draw() {
    stroke(0);
    strokeWeight(2);
    fill(lerpColor(color(255, 200, 0), color(255), constrain(velocity.mag(), 0, 1)));
    ellipse(x, y, size, size);
    for (PVector p : trail) {
      noStroke();
      fill(0, 100);
      ellipse(p.x, p.y, size * 0.6, size * 0.6);
    }
  }

  void fire(float power, float angle) {
    if (!isFired) {
      this.velocity = new PVector(power * cos(angle), power * sin(angle));
      isFired = true;
    }
  }

  boolean checkCollision(float otherX, float otherY, float otherSize) {
    float d = dist(x, y, otherX, otherY);
    return d < size / 2 + otherSize / 2;
  }
}

