      resetStone();
      stationaryStone = new Stone(20, width / 4, height / 2, 0.3, false); // 重新设置静止的球
      score++; // 增加分数
    }
    pollution.draw();
  }

  stone.update();
  stone.draw();

  // 检查玩家控制的球是否与静止的球碰撞
  if (stone.isFired && !stationaryStone.isFired
    && stone.checkCollision(stationaryStone.x, stationaryStone.y, stationaryStone.size)) {
    handleCollision();
  }

  if (stationaryStone.isFired) {
    stationaryStone.update();
  }

  if (stone.x > width || stone.y < 0 || stone.y > height || stationaryStone.x > width) {
    resetStone();
    stationaryStone = new Stone(20, width / 4, height / 2, 0.3, false);
  }

  if (charging) {
    float chargeRadius = map(millis() - mousePressedTime, 0, 1000, stone.size, stone.size * 3);
    noFill();
    stroke(255, 0, 0);
    ellipse(stone.x, stone.y, chargeRadius * 2, chargeRadius * 2);
  }

  stroke(0);
  if (mousePressed && !isFired) {
    line(stone.x, stone.y, mouseX, mouseY);
  }

  fill(0);
  textAlign(RIGHT, TOP);
  textSize(24);
  text("Score: " + score, width - 20, 20);
}

// 其他函数保持不变...
```

请注意，根据这个新逻辑，`handleHitPollution()` 函数现在被调用在静止的球（stationaryStone）击中污染物后，而不是玩家控制的球（stone）直接击中污染物。此外，我们也在击中污染物之后重置了静止的球和玩家控制的球。

这样，你的游戏现在就会有类似桌球的逻辑，即玩家控制的球必须先击中另一个球，由那个球去击中污染物。这符合你想要模仿桌球的击球逻辑，并且在污染物被击中时会增加分数。

要实现手上射出去的球在碰到边界时反弹，但是当另一个被碰撞的球碰到边界时不会反弹，我们需要为两种球制定不同的反弹逻辑。对于手上射出去的球（stone），我们会检测边界，并相应地逆转其速度向量的X或Y分量。对于被碰撞的球（stationaryStone），如果它接触到边界，那么它就会停止移动，并准备下一次发射。

以下是 `Stone` 类中更新方法 `update()` 的示例代码，该代码包含边界检测和反弹逻辑：

```java
void update() {
  if (isFired) {
    acceleration.add(new PVector(0, gravity));
    velocity.add(acceleration);
    x += velocity.x;
    y += velocity.y;
    acceleration.mult(0);

    // 检查并处理边界碰撞
    if (x > width - size/2 || x < size/2) {
      velocity.x *= -1; // 反弹逻辑
      x = constrain(x, size/2, width - size/2); // 防止移出边界
    }

    if (y > height - size/2 || y < size/2) {
      velocity.y *= -1; // 同上，对Y分量
      y = constrain(y, size/2, height - size/2); // 同上
    }

