class Stone {
  float size;
  float x, y;
  PVector velocity;
  PVector acceleration;
  float gravity;
  boolean isFired;
  PImage texture; // 添加图案纹理
  ArrayList<PVector> trail;

  Stone(float size, float x, float y, float gravity, boolean isFired, PImage texture) {
    this.size = size;
    this.x = x;
    this.y = y;
    this.gravity = gravity;
    velocity = new PVector(0, 0);
    trail = new ArrayList<PVector>();
    this.isFired = isFired;
    this.texture = texture; // 将传入的图案纹理存储到对象变量中
  }

  void update() {
    if (isFired) {
      acceleration.add(new PVector(0, gravity));
      velocity.add(acceleration);
      x += velocity.x;
      y += velocity.y;
      acceleration.mult(0);

      // 当石头发射时，添加到轨迹历史里，这样可以绘制尾迹
      trail.add(new PVector(x, y));
      if (trail.size() > 10) {
        trail.remove(0); // 限制轨迹长度
      }
    }
  }

  void draw() {
    // 绘制尾迹效果
    for (PVector p : trail) {
      fill(200, 200);
      noStroke();
      ellipse(p.x, p.y, size * 0.5, size * 0.5);
    }

    // 使用 image() 函数绘制石头纹理
    if (texture != null) {
      imageMode(CENTER);
      image(texture, x, y, size, size);
    } else {
      // 如果图片未加载成功，则绘制一个简单的石头形状
      fill(127); // 石头颜色
      stroke(255); // 石头边框颜色
      ellipse(x, y, size, size);
    }
  }

  void fire(float power, float angle) {
    if (!isFired) {
      velocity = new PVector(power * cos(angle), power * sin(angle));
      isFired = true;
    }
  }

  boolean checkCollision(float otherX, float otherY, float otherSize) {
    float d = dist(x, y, otherX, otherY);
    return d < (size / 2 + otherSize / 2);
  }
}
